SELECT ,
       (SELECT COUNT(*) FROM student s WHERE s.class_id = c.id AND s.is_deleted = 0) as student_count
FROM class_entity c
LEFT JOIN sys_user u ON c.teacher_id = u.id
WHERE c.is_deleted = 0

    AND c.class_name LIKE CONCAT('%', #{className}, '%')


    AND c.grade = #{grade}


    AND c.teacher_id = #{teacherId}

ORDER BY c.grade ASC, c.class_name ASC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM class_entity c
WHERE c.is_deleted = 0

    AND c.class_name LIKE CONCAT('%', #{className}, '%')


    AND c.grade = #{grade}


    AND c.teacher_id = #{teacherId}

SELECT id, class_name
FROM class_entity
WHERE class_name = #{className}
AND is_deleted = 0

    AND id != #{excludeId}

LIMIT 1
